21: /**
22:  * Pricer for FX vanilla option trades with a Vanna-Volga method.
23:  * <p>
24:  * The volatilities are expressed using {@code BlackFxOptionSmileVolatilities}. 
25:  * Each smile of the term structure consists of 3 data points, where the middle point corresponds to ATM volatility.
26:  */
27: public class VannaVolgaFxVanillaOptionTradePricer {
28: 
29:   /**
30:    * Default implementation.
31:    */
32:   public static final VannaVolgaFxVanillaOptionTradePricer DEFAULT = new VannaVolgaFxVanillaOptionTradePricer(
33:       VannaVolgaFxVanillaOptionProductPricer.DEFAULT,
34:       DiscountingPaymentPricer.DEFAULT);
35: 
36:   /**
37:    * Pricer for {@link ResolvedFxSingleBarrierOption}.
38:    */
39:   private final VannaVolgaFxVanillaOptionProductPricer productPricer;
40:   /**
41:    * Pricer for {@link Payment}.
42:    */
43:   private final DiscountingPaymentPricer paymentPricer;
44: 
45:   /**
46:    * Creates an instance.
47:    * 
48:    * @param productPricer  the pricer for {@link ResolvedFxVanillaOption}
49:    * @param paymentPricer  the pricer for {@link Payment}
50:    */
51:   public VannaVolgaFxVanillaOptionTradePricer(
52:       VannaVolgaFxVanillaOptionProductPricer productPricer,
53:       DiscountingPaymentPricer paymentPricer) {
54:     this.productPricer = ArgChecker.notNull(productPricer, "productPricer");
55:     this.paymentPricer = ArgChecker.notNull(paymentPricer, "paymentPricer");
56:   }
57: 
58:   //-------------------------------------------------------------------------
59:   /**
60:    * Calculates the present value of the FX vanilla option trade.
61:    * <p>
62:    * The present value of the trade is the value on the valuation date.
63:    * 
64:    * @param trade  the option trade
65:    * @param ratesProvider  the rates provider
66:    * @param volatilities  the Black volatility provider
67:    * @return the present value of the trade
68:    */
69:   public MultiCurrencyAmount presentValue(
70:       ResolvedFxVanillaOptionTrade trade,
71:       RatesProvider ratesProvider,
72:       BlackFxOptionSmileVolatilities volatilities) {
73: 
74:     ResolvedFxVanillaOption product = trade.getProduct();
75:     CurrencyAmount pvProduct = productPricer.presentValue(product, ratesProvider, volatilities);
76:     Payment premium = trade.getPremium();
77:     CurrencyAmount pvPremium = paymentPricer.presentValue(premium, ratesProvider);
78:     return MultiCurrencyAmount.of(pvProduct, pvPremium);
79:   }
80: 
81:   //-------------------------------------------------------------------------
82:   /**
83:    * Calculates the present value sensitivity of the FX vanilla option trade.
84:    * <p>
85:    * The present value sensitivity of the trade is the sensitivity of the present value to
86:    * the underlying curves.
87:    * <p>
88:    * The volatility is fixed in this sensitivity computation.
89:    * 
90:    * @param trade  the option trade
91:    * @param ratesProvider  the rates provider
92:    * @param volatilities  the Black volatility provider
93:    * @return the present value curve sensitivity of the trade
94:    */
95:   public PointSensitivities presentValueSensitivityRatesStickyStrike(
96:       ResolvedFxVanillaOptionTrade trade,
97:       RatesProvider ratesProvider,
98:       BlackFxOptionSmileVolatilities volatilities) {
99: 
100:     ResolvedFxVanillaOption product = trade.getProduct();
101:     PointSensitivities pvcsProduct =
102:         productPricer.presentValueSensitivityRatesStickyStrike(product, ratesProvider, volatilities).build();
103:     Payment premium = trade.getPremium();
104:     PointSensitivities pvcsPremium = paymentPricer.presentValueSensitivity(premium, ratesProvider).build();
105:     return pvcsProduct.combinedWith(pvcsPremium);
106:   }
107: 
108:   //-------------------------------------------------------------------------
109:   /**
110:    * Computes the present value sensitivity to the black volatility used in the pricing.
111:    * <p>
112:    * The result is a single sensitivity to the volatility used.
113:    * 
114:    * @param trade  the option trade
115:    * @param ratesProvider  the rates provider
116:    * @param volatilities  the Black volatility provider
117:    * @return the present value sensitivity
118:    */
119:   public PointSensitivities presentValueSensitivityModelParamsVolatility(
120:       ResolvedFxVanillaOptionTrade trade,
121:       RatesProvider ratesProvider,
122:       BlackFxOptionSmileVolatilities volatilities) {
123: 
124:     ResolvedFxVanillaOption product = trade.getProduct();
125:     return productPricer.presentValueSensitivityModelParamsVolatility(product, ratesProvider, volatilities).build();
126:   }
127: 
128:   //-------------------------------------------------------------------------
129:   /**
130:    * Calculates the currency exposure of the FX vanilla option trade.
131:    * 
132:    * @param trade  the option trade
133:    * @param ratesProvider  the rates provider
134:    * @param volatilities  the Black volatility provider
135:    * @return the currency exposure
136:    */
137:   public MultiCurrencyAmount currencyExposure(
138:       ResolvedFxVanillaOptionTrade trade,
139:       RatesProvider ratesProvider,
140:       BlackFxOptionSmileVolatilities volatilities) {
141: 
142:     Payment premium = trade.getPremium();
143:     CurrencyAmount pvPremium = paymentPricer.presentValue(premium, ratesProvider);
144:     ResolvedFxVanillaOption product = trade.getProduct();
145:     return productPricer.currencyExposure(product, ratesProvider, volatilities).plus(pvPremium);
146:   }
147: 
148:   //-------------------------------------------------------------------------
149:   /**
150:    * Calculates the current of the FX vanilla option trade.
151:    * 
152:    * @param trade  the option trade
153:    * @param valuationDate  the valuation date
154:    * @return the current cash amount
155:    */
156:   public CurrencyAmount currentCash(ResolvedFxVanillaOptionTrade trade, LocalDate valuationDate) {
157:     Payment premium = trade.getPremium();
158:     if (premium.getDate().equals(valuationDate)) {
159:       return CurrencyAmount.of(premium.getCurrency(), premium.getAmount());
160:     }
161:     return CurrencyAmount.of(premium.getCurrency(), 0d);
162:   }
163: 
164: }
